// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor positioned on the motor shaft of the first axis, measuring electrical current to infer torque."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder mounted on the motor shaft of the first axis, providing motor angular position."
    DTDFVocab:producedData MotorAngleDataTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder mounted on the gearbox output of the first axis, providing gearbox angular position."
    DTDFVocab:producedData GearboxOutputAngleDataTransmitted
]

instance CNCPositionSensor : DTDFVocab:SensingComponent [
    base:desc "Position sensor used by the CNC controller to provide reference positions for the first axis."
    DTDFVocab:producedData CNCPositionDataTransmitted
]

// C4: Physical-to-virtual interaction
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxOutputAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance CNCPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom CNCPositionSensor
]

// C10: Models/Data – derived data
instance MotorCurrentData : DTDFVocab:Data [
