    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Time-series data of motor angular position received via MQTT from MotorEncoder."
    DTDFVocab:fromData MotorAngleDataTransmitted
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance GearboxOutputAngleData : DTDFVocab:Data [
    base:desc "Time-series data of gearbox output angular position received via MQTT from GearboxEncoder."
