    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance AccelerationData : DTDFVocab:Data [
    base:desc "Simulated angular acceleration derived from angular velocity data in the Simulink system."
    DTDFVocab:fromData AngularVelocityData
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

// C10: Models
instance MotorSimulinkModel : DTDFVocab:Model [
    base:desc "Simulink model of the motor incorporating Coulomb, viscous, Stribeck, Dahl, and LuGre friction submodels."
