]

instance GearboxSimulinkModel : DTDFVocab:Model [
    base:desc "Simulink model of the gearbox capturing gear train dynamics and friction elements."
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance RobotSystemSimulinkModel : DTDFVocab:Model [
    base:desc "Integrated Simulink model of the first axis of the MABI MAX 100, combining motor, gearbox, and system dynamics."
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

